from dataclasses import dataclass@dataclass(slots=True)class Detector:    """    One CRIRES+ detector within an echelle order.    """    number: int    wavelength_min: float    wavelength_max: float    '''    Properties    '''    @property    def width(self) -> float:        return self.wavelength_max - self.wavelength_min    @property    def wavelength_center(self) -> float:        return 0.5 * (            self.wavelength_min +            self.wavelength_max        )    @property    def wavelengths(self):        return (            self.wavelength_min,            self.wavelength_max,        )        '''    Methods    '''    def __str__(self):        return (            f"Detector {self.number}: "            f"{self.wavelength_min:.3f}–"            f"{self.wavelength_max:.3f} μm"        )        def __contains__(self, wavelength: float) -> bool:        return (            self.wavelength_min            <= wavelength            <= self.wavelength_max        )